-- ============================================================
-- Migration: 2026-03-09_040_demo_in_db.sql
-- Purpose  : Move demo seeding from JS to DB-native PL/pgSQL.
--            New users receive demo data via handle_new_user trigger.
--            Demo restoration calls restore_my_demo() RPC.
-- ============================================================

-- 1. gen_random_bytes wrapper
--    gen_share_key calls bare gen_random_bytes() but pgcrypto lives in
--    the extensions schema.  This public wrapper is found first in search_path.
CREATE OR REPLACE FUNCTION public.gen_random_bytes(n integer)
  RETURNS bytea LANGUAGE sql STABLE AS $$
  SELECT extensions.gen_random_bytes(n);
$$;

-- 2. Add is_demo columns (idempotent)
ALTER TABLE public.games          ADD COLUMN IF NOT EXISTS is_demo boolean NOT NULL DEFAULT false;
ALTER TABLE public.user_logos     ADD COLUMN IF NOT EXISTS is_demo boolean NOT NULL DEFAULT false;
ALTER TABLE public.question_bases ADD COLUMN IF NOT EXISTS is_demo boolean NOT NULL DEFAULT false;

-- 3. user_flags.demo default → false (seeding now happens at registration)
ALTER TABLE public.user_flags ALTER COLUMN demo SET DEFAULT false;

-- 4. Template table
CREATE TABLE IF NOT EXISTS public.demo_template_data (
  lang    text  NOT NULL,
  slot    text  NOT NULL,
  payload jsonb NOT NULL,
  PRIMARY KEY (lang, slot)
);
ALTER TABLE public.demo_template_data ENABLE ROW LEVEL SECURITY;
-- No RLS policies: accessible only through SECURITY DEFINER functions

-- 5. Template data (3 langs × 12 slots = 36 rows)

